-- 1. Dartford × Web Design
INSERT INTO public.local_content (service_slug, town_slug, intro_paragraph, local_context, competition_landscape, success_approach, local_stats, pain_points, solutions, faqs, layout_variant)
VALUES (
  'web-design',
  'dartford',
  'Dartford sits at one of the busiest transport junctions in the South East. The Dartford Crossing carries over fifty million vehicle journeys a year, Ebbsfleet International station puts London St Pancras just seventeen minutes away by high-speed rail, and the town centre is undergoing significant regeneration that is reshaping the commercial landscape. With a borough population exceeding one hundred and ten thousand and Bluewater Shopping Centre just minutes away raising consumer expectations, Dartford businesses operate in a market where digital presentation is judged against metropolitan standards. Commuters who work in London expect seamless online experiences from their local service providers. Businesses competing near Bluewater need websites that match the polish of national retail brands. We build bespoke, conversion-focused websites for Dartford businesses that meet these elevated expectations and turn the town''s exceptional connectivity into a genuine commercial advantage.',
  'Dartford''s geography and infrastructure define its commercial character. The Dartford Crossing and M25 junction create a logistics and distribution hub that supports a significant warehouse and transport sector. Ebbsfleet International station, with its seventeen-minute connection to London St Pancras via HS1, has attracted a commuter demographic with high digital expectations. The town centre regeneration around the High Street and Central Park is creating new commercial and residential spaces. The Orchard Theatre provides a cultural anchor. Dartford Grammar School and local educational institutions contribute to the community fabric. The Mick Jagger Centre adds a distinctive cultural landmark. Bluewater''s proximity shapes retail expectations across the area.',
  'Dartford''s web design market is influenced by the town''s proximity to London and Bluewater. London agencies serve the commuter market at premium rates, while budget freelancers compete for price-sensitive local businesses. The logistics and warehouse sector has minimal web presence, relying on B2B relationships rather than digital visibility. The regenerating town centre has attracted newer businesses with more modern websites, but established trades and services frequently operate outdated sites that fail to compete for the attention of Dartford''s digitally sophisticated commuter population.',
  'Our approach for Dartford clients starts with understanding the commuter mindset. Residents who reach London in seventeen minutes via Ebbsfleet bring home expectations shaped by the best digital experiences in the country. We build websites optimised for evening mobile browsing, when commuters research local services on the train home. For businesses in the logistics sector, we create professional B2B sites that establish credibility. For town centre businesses competing near Bluewater, we build sites that match national retail standards.',
  '{"population": 110000, "growth": "Significant town centre regeneration and transport-led growth", "business_districts": ["High Street", "Central Park area", "Dartford Crossing logistics zone", "Ebbsfleet vicinity"], "key_fact": "17 minutes to London St Pancras via HS1 at Ebbsfleet creates strong commuter demographic"}',
  '[{"title": "Commuter expectations outpacing Dartford business websites", "description": "Dartford''s commuters spend their working days surrounded by the polished digital experiences of London businesses. When they search for a local tradesperson or restaurant in the evening, they carry those expectations home. Businesses around the High Street and Central Park with dated, clunky websites are losing customers to competitors who present a more professional digital image."}, {"title": "Bluewater proximity raising digital standards for Dartford businesses", "description": "Dartford residents shop at Bluewater regularly, experiencing the websites and digital services of major national brands. When they then search for a local Dartford business and find a slow, outdated site with stock imagery, the contrast is stark. The proximity of world-class retail raises the bar that every local business website is judged against."}, {"title": "Logistics sector invisible online despite Dartford dominance", "description": "The warehouse, distribution, and logistics businesses clustered around the Dartford Crossing and M25 corridor represent a massive economic sector with almost zero web presence. As B2B procurement increasingly moves online, logistics companies without professional websites are losing contracts to competitors who present more credibly in digital searches."}]',
  '[{"title": "Commuter-grade websites for Dartford businesses", "description": "We design sites that meet the digital standards Dartford''s London commuters expect. Clean, modern layouts with sub-two-second load times, intuitive mobile navigation optimised for train browsing, and conversion paths that turn evening research sessions into morning enquiries. Your website should match the speed and polish of the HS1 connection."}, {"title": "B2B web design for Dartford''s logistics sector", "description": "Professional websites for warehouse, distribution, and logistics businesses that establish credibility with procurement teams. Clear service presentations, capability showcases, compliance documentation, and enquiry funnels designed for the B2B decision-making process. Built for the businesses that power the Dartford Crossing economy."}, {"title": "Retail-competitive design for Dartford town centre", "description": "Websites that compete visually with the national brands Dartford residents encounter at Bluewater. Bespoke design, professional photography, and polished user experience that positions your Dartford business as the quality local alternative to the chain stores and national providers."}]',
  '[{"question": "How long does a new website take for a Dartford business?", "answer": "Most Dartford projects launch within four to six weeks. We start with a strategy session understanding your position in the local market, your target audience across the borough and surrounding areas, and your competitive landscape relative to both local competitors and nearby Bluewater retailers."}, {"question": "Will my site work for Dartford commuters browsing on mobile?", "answer": "Absolutely. Mobile performance is our top priority for Dartford sites. We design for the commuter browsing pattern: quick research on a phone during the seventeen-minute Ebbsfleet journey or longer Dartford station commute. Fast loading, easy navigation, and prominent call-to-action buttons optimised for mobile interaction."}, {"question": "Do you build websites for logistics and warehouse businesses?", "answer": "Yes. We have specific experience building B2B websites for the logistics, distribution, and warehouse sector that clusters around the Dartford Crossing and M25 corridor. These sites are designed for the professional procurement audience, with clear capability presentations and structured enquiry processes."}, {"question": "Can you redesign my existing Dartford business website?", "answer": "Yes. We audit your current site, preserve any existing search authority through proper redirects, and deliver a modern redesign that meets the expectations of Dartford''s digitally sophisticated customer base. Most redesigns are complete within four to six weeks."}]',
  'lead-gen'
)
ON CONFLICT (service_slug, town_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
