-- 3. Dartford × Lead Capture
INSERT INTO public.local_content (service_slug, town_slug, intro_paragraph, local_context, competition_landscape, success_approach, local_stats, pain_points, solutions, faqs, layout_variant)
VALUES (
  'lead-capture',
  'dartford',
  'Dartford''s one hundred and ten thousand residents live in one of the best-connected boroughs in Kent, and their browsing habits reflect that connectivity. Commuters research local services during the seventeen-minute Ebbsfleet journey, comparing options on their phones and fully intending to call tomorrow. They never do. Homeowners in the regeneration areas around the town centre submit enquiry forms at seven in the evening and expect a response before bedtime. Logistics managers comparing warehouse options from their Dartford Crossing offices need detailed capability information before they will share contact details. Each of these audiences requires a different lead capture approach, and a basic contact form fails all of them. Our lead capture systems are engineered for the diverse Dartford market, converting commuter browsers, residential enquirers, and B2B prospects into named, contactable leads before they move on to a competitor.',
  'Dartford''s lead generation landscape is defined by its transport connectivity and demographic mix. The commuter population using Ebbsfleet and Dartford station researches local services during predictable travel windows. The residential areas generate standard home service enquiries, concentrated in evenings and weekends. The logistics and warehouse sector around the Dartford Crossing produces B2B leads with longer decision cycles and different information requirements. The town centre regeneration is bringing younger demographics with digital-first expectations. Bluewater''s proximity means local businesses must capture customer interest before it defaults to the shopping centre''s options.',
  'Lead capture sophistication among Dartford businesses is minimal. The vast majority rely on a phone number and a contact form. Some Dartford Crossing logistics businesses have basic enquiry forms on their websites, but with no automation or follow-up systems. Residential service businesses have almost no structured lead capture. The commuter demographic, accustomed to the instant-response digital experiences of London businesses, finds Dartford''s manual approach frustratingly slow.',
  'We design lead capture for each Dartford audience segment. Commuter browsers get timed capture elements optimised for the train browsing window, offering instant callbacks the next morning. Residential prospects get quote calculators and callback booking tools that engage evening browsers. B2B logistics prospects get capability guides, detailed specification forms, and consultation booking tools appropriate to their longer decision cycle. Every system includes automated follow-up matching the response expectations of each audience.',
  '{"population": 110000, "growth": "Regeneration and commuter growth expanding the market", "business_districts": ["High Street", "Dartford Crossing corridor", "Ebbsfleet area", "Central Park"], "key_fact": "Commuter demographic expects instant digital responses matching London business standards"}',
  '[{"title": "Commuter browsers researching on the train but never converting", "description": "Dartford commuters research local services during the Ebbsfleet journey home. They browse three or four options, fully intending to call tomorrow. By morning, they have forgotten which business looked best. Without capturing their details during that critical browsing window, your Dartford website generates awareness but zero leads from this high-value audience."}, {"title": "Evening enquiries going cold overnight in Dartford", "description": "A Dartford homeowner submits a contact form at eight in the evening after seeing your van in their street. You reply at eight-thirty the next morning. By then, the two competitors with automated acknowledgement and callback booking have already secured the lead. Manual response times cannot compete with automated systems in a commuter town."}, {"title": "B2B logistics leads needing information before sharing details", "description": "A procurement manager researching Dartford Crossing warehouse options will not fill in a basic contact form without understanding your capabilities first. Without offering detailed information in exchange for contact details, logistics businesses lose B2B prospects who are actively evaluating but not yet ready to speak to sales."}]',
  '[{"title": "Commuter-timed lead capture for train browsers", "description": "We implement scroll-triggered and timed capture elements optimised for the Dartford commuter browsing window. Mobile-first callback request tools let Ebbsfleet and Dartford station commuters book a morning call in seconds, capturing their details during the narrow window when they are actively researching local services."}, {"title": "Automated follow-up matching Dartford response expectations", "description": "Every lead captured from your Dartford website triggers an immediate personalised acknowledgement followed by a timed nurture sequence. Evening enquirers receive professional communication before they sleep. Morning leads get same-hour responses. Your Dartford business responds at the speed this commuter market demands."}, {"title": "B2B lead capture for Dartford logistics and commercial businesses", "description": "We build capability guides, specification request forms, and consultation booking tools that B2B prospects willingly exchange contact details for. A logistics manager evaluating Dartford Crossing warehouse options gets the detailed information they need while you get a qualified lead with defined requirements."}]',
  '[{"question": "What lead capture works best for Dartford commuter audiences?", "answer": "Timed callback request tools and instant-access guides perform best for the commuter demographic. These elements capture details during the narrow train browsing window and offer immediate value. The prospect books a morning callback in seconds, and your automated system confirms the appointment before they leave the station."}, {"question": "Can lead capture work for Dartford logistics businesses?", "answer": "Yes. B2B lead capture requires a different approach to consumer markets. We build capability download tools, specification request forms, and consultation booking systems that logistics procurement managers willingly engage with. The key is offering valuable information that aids their decision process in exchange for contact details."}, {"question": "How quickly will I see leads from the new system?", "answer": "Most Dartford clients see captured leads within the first week. The volume depends on existing website traffic, but even sites with modest visitor numbers typically see a two to four times increase in monthly enquiries once proper lead capture is implemented. Commuter-targeted capture elements often produce results within the first few days."}, {"question": "Will pop-ups annoy my Dartford website visitors?", "answer": "Only if they are poorly implemented. Our capture elements are strategically timed, exit-intent triggered, and offer genuine value. Dartford commuters respond well to callback booking tools that solve a real problem. When the offer is useful and the timing is right, capture elements consistently convert three to eight percent of visitors."}]',
  'lead-gen'
)
ON CONFLICT (service_slug, town_slug) DO UPDATE SET
