-- 6. Dartford × Social Media Setup
INSERT INTO public.local_content (service_slug, town_slug, intro_paragraph, local_context, competition_landscape, success_approach, local_stats, pain_points, solutions, faqs, layout_variant)
VALUES (
  'social-media-setup',
  'dartford',
  'Social media in Dartford reaches a borough of over one hundred and ten thousand people, with additional potential to attract the commuter demographic that flows through Ebbsfleet and Dartford station daily. Yet most Dartford businesses treat social media as an afterthought. Dormant Facebook pages, inactive Instagram accounts, and zero presence on LinkedIn where the logistics sector could be building B2B relationships. The businesses that do maintain active, professional social profiles in Dartford are absorbing a disproportionate share of local engagement because they have so little competition. The opportunity is clear: in a town where most businesses have abandoned or neglected their social media, even a professionally set up and modestly maintained presence stands out dramatically. We build social media foundations for Dartford businesses that are strategically configured to reach the right audience across the borough and beyond.',
  'Dartford''s social media landscape is shaped by its demographic diversity. The commuter population is active on LinkedIn and Instagram, influenced by London trends and brands. The established residential community uses Facebook as its primary social platform for local discovery and recommendations. The logistics and commercial sector has minimal social media presence despite LinkedIn being a natural B2B channel. The town centre regeneration creates content opportunities around new developments, the Orchard Theatre, and Central Park events. Dartford FC generates community engagement that local businesses could leverage. The Mick Jagger Centre adds a distinctive cultural content angle unique to Dartford.',
  'Social media quality among Dartford businesses is generally poor. A handful of town centre businesses maintain active Facebook pages, but professional, strategically managed social profiles are rare. The logistics sector is almost entirely absent from LinkedIn despite the clear B2B opportunity. Instagram is underutilised by hospitality and retail businesses that could leverage visual content. The low standard means the barrier to standing out is remarkably achievable for any business willing to invest in proper setup.',
  'We set up Dartford social profiles with audience-specific configurations for each platform. Facebook targets the established borough community with local content and recommendations. Instagram showcases your business visually for the aspirational commuter demographic. LinkedIn positions logistics and professional service businesses for B2B relationships across the Dartford commercial corridor. Brand-consistent templates and content calendars ensure professional output from day one.',
  '{"population": 110000, "growth": "Growing through regeneration with expanding social media audience", "business_districts": ["High Street", "Dartford Crossing corridor", "Ebbsfleet area", "Central Park"], "key_fact": "Very low social media competition creates easy-win opportunities for professionally set up profiles"}',
  '[{"title": "Dormant Dartford business profiles driving customers away", "description": "A Dartford resident checks your Facebook page before visiting your business. The last post was four months ago and the cover photo shows your old signage. They question whether you are still trading and choose a competitor with an active, professional profile instead. Dormant social media is worse than no social media in a town of a hundred and ten thousand people."}, {"title": "Zero LinkedIn presence in Dartford''s logistics sector", "description": "The logistics, haulage, and warehouse businesses around the Dartford Crossing have almost no LinkedIn presence despite it being the primary platform for B2B relationship building. Procurement managers and commercial clients who search LinkedIn find nothing, while competitors in other regions are building visibility and authority on the platform."}, {"title": "Commuter demographics unreached by Dartford business social media", "description": "Dartford''s Ebbsfleet commuters follow London brands and influencers on Instagram and LinkedIn. Local Dartford businesses with no presence on these platforms are invisible to a high-spending demographic that lives in the borough and wants to support local businesses but cannot find them on the platforms they use daily."}]',
  '[{"title": "Multi-platform social media setup for Dartford", "description": "We configure Facebook for community engagement, Instagram for visual brand building, and LinkedIn for B2B positioning. Each platform is set up with optimised profiles, branded visuals, and content structures targeting the specific Dartford audience that uses it. Complete setup across all relevant platforms from day one."}, {"title": "LinkedIn setup for Dartford logistics and commercial businesses", "description": "We build professional LinkedIn company pages and content strategies for Dartford Crossing logistics businesses. Industry-relevant content, company updates, and B2B positioning that establishes your operation as a credible, professional partner in the minds of procurement teams and commercial contacts."}, {"title": "Brand-consistent templates and content calendars", "description": "We deliver a library of branded templates for posts, stories, and articles alongside a content calendar structured around Dartford events, seasons, and business milestones. Any team member can maintain professional posting without design skills, ensuring consistency across every platform."}]',
  '[{"question": "Which social media platforms matter for Dartford businesses?", "answer": "Facebook is essential for reaching the established borough community. Instagram matters for hospitality, retail, and any business targeting the commuter demographic. LinkedIn is critical for logistics, professional services, and B2B businesses around the Dartford Crossing corridor. We recommend the specific combination that matches your audience."}, {"question": "Can social media help Dartford logistics businesses?", "answer": "Yes, specifically through LinkedIn. B2B relationships increasingly begin with online research, and LinkedIn is where procurement managers evaluate potential partners. A professionally set up LinkedIn presence positions your Dartford Crossing operation credibly in a sector where almost no local competitor has any LinkedIn visibility."}, {"question": "How do you set up social media for a Dartford business?", "answer": "We configure profiles across each relevant platform with optimised bios, branded cover images and profile photos, content categories, and posting schedules. We deliver templates, a content calendar, and guidelines that enable you or your team to maintain a professional presence independently."}, {"question": "Do you manage social media ongoing or just set it up?", "answer": "This service covers professional setup and strategic foundations. We deliver fully configured profiles, content calendars, branded templates, and detailed guidelines. Ongoing management is available separately if you prefer hands-off social media. Many Dartford clients use the setup to manage posting themselves with the templates provided."}]',
  'trust'
)
ON CONFLICT (service_slug, town_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
